import{_ as e,o as t,c as s,a2 as o}from"./chunks/framework.BWuWLRhz.js";const u=JSON.parse('{"title":"什么是 CZero","description":"","frontmatter":{},"headers":[],"relativePath":"guide/what-is-czero.md","filePath":"guide/what-is-czero.md","lastUpdated":1783223243000}'),n={name:"guide/what-is-czero.md"};function d(r,a,i,l,c,p){return t(),s("div",null,[...a[0]||(a[0]=[o(`<h1 id="什么是-czero" tabindex="-1">什么是 CZero <a class="header-anchor" href="#什么是-czero" aria-label="Permalink to &quot;什么是 CZero&quot;">​</a></h1><p>CZero 是一个 Android Root 清理模块，为常见的高频应用提供缓存清理，并涵盖后台压制、空文件夹清理与 F2FS 垃圾回收。</p><p>模块本身没有常驻服务，由一个轻量 C++ 守护进程按 <code>config.json</code> 调度所有任务，配置修改即时生效。日常操作通过原生配套应用 <strong>CZeroX</strong> 完成。</p><h2 id="它解决什么问题" tabindex="-1">它解决什么问题 <a class="header-anchor" href="#它解决什么问题" aria-label="Permalink to &quot;它解决什么问题&quot;">​</a></h2><p>长期使用后，应用缓存与后台常驻会持续占用存储和内存，手机逐渐变卡、可用空间变少。CZero 在后台按计划自动完成清理与压制，让设备保持干净、流畅，无需手动干预。</p><h2 id="设计理念" tabindex="-1">设计理念 <a class="header-anchor" href="#设计理念" aria-label="Permalink to &quot;设计理念&quot;">​</a></h2><ul><li><strong>无常驻服务</strong> —— 不驻留任何 Java 进程，调度全部交给一个基于 <code>timerfd</code> + <code>epoll</code> 的微型 C++ 守护进程，开销趋近于零。</li><li><strong>单一配置源</strong> —— 所有行为集中在一份 <code>config.json</code>，守护进程与各清理组件直接读取，无中间派生文件。</li><li><strong>即时生效</strong> —— 守护进程监视 <code>config.json</code> 的变更并热重载；配置损坏时保留上一份有效任务，绝不中断。</li><li><strong>原生前端</strong> —— 日常操作通过原生应用 CZeroX 完成，不依赖 WebUI。</li></ul><h2 id="三层架构" tabindex="-1">三层架构 <a class="header-anchor" href="#三层架构" aria-label="Permalink to &quot;三层架构&quot;">​</a></h2><p>CZero 由三个协同工作的层组成：</p><table tabindex="0"><thead><tr><th>层</th><th>组件</th><th>职责</th></tr></thead><tbody><tr><td>安装</td><td><code>customize.sh</code></td><td>音量键选择语言、询问是否继承旧配置</td></tr><tr><td>开机</td><td><code>service.sh</code> → <code>service</code>（C++）</td><td>标记模块生效、初始化统计文件、修正权限、拉起守护进程</td></tr><tr><td>运行时</td><td><code>cron/timer_daemon</code>（C++）</td><td>解析 <code>config.json</code>、调度并派生全部清理任务、变更即热重载</td></tr></tbody></table><h2 id="运行时文件" tabindex="-1">运行时文件 <a class="header-anchor" href="#运行时文件" aria-label="Permalink to &quot;运行时文件&quot;">​</a></h2><p>所有运行时文件位于 <code>/data/adb/modules/CZero/</code>：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>config.json            # 唯一配置源（守护进程与各清理组件直接读取）</span></span>
<span class="line"><span>basis/basis.prop       # 清理统计</span></span>
<span class="line"><span>cron/state             # ≥1 天任务的上次执行时间</span></span>
<span class="line"><span>list/Tencent/…         # 高频应用检测与清理脚本</span></span>
<span class="line"><span>list/suppress/…        # 后台压制</span></span>
<span class="line"><span>list/GCclean/…         # F2FS GC 脚本</span></span>
<span class="line"><span>list/Emptyfolder/…     # 空文件夹清扫</span></span>
<span class="line"><span>log/&lt;YYYY-MM-DD&gt;.log   # 单一每日日志（仅保留当天）</span></span></code></pre></div><h2 id="环境要求" tabindex="-1">环境要求 <a class="header-anchor" href="#环境要求" aria-label="Permalink to &quot;环境要求&quot;">​</a></h2><ul><li>Android 9+（API 28），<code>arm64-v8a</code></li><li>Root 方案：Magisk、KernelSU 或 APatch</li><li>F2FS <code>/data</code> 分区（仅 GC 功能需要，其余功能不受影响）</li></ul><p>准备好后，前往 <a href="/guide/getting-started">安装与上手</a>。</p>`,16)])])}const g=e(n,[["render",d]]);export{u as __pageData,g as default};
